1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block pattern alive where each cell has exactly 3 neighbors (survival)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    const plus: [number, number][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
21	    const result = nextGeneration(plus);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
25	    const liveCells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
26	    const result = nextGeneration(liveCells);
27	    expect(result).toContainEqual([1, 1]);
28	  });
29	  it.todo("should evolve a blinker from vertical to horizontal (oscillator)");
30	});
31

1	export type Cell = [number, number];
2	
3	const neighborPositions = ([x, y]: Cell): Cell[] => {
4	  const offsets = [-1, 0, 1];
5	  const positions: Cell[] = [];
6	  for (const dx of offsets) {
7	    for (const dy of offsets) {
8	      if (dx === 0 && dy === 0) continue;
9	      positions.push([x + dx, y + dy]);
10	    }
11	  }
12	  return positions;
13	};
14	
15	const isAlive = (cell: Cell, liveCells: Cell[]): boolean =>
16	  liveCells.some(([lx, ly]) => lx === cell[0] && ly === cell[1]);
17	
18	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
19	  neighborPositions(cell).filter((neighbor) => isAlive(neighbor, liveCells)).length;
20	
21	const findDeadNeighbors = (liveCells: Cell[]): Cell[] => {
22	  const seen = new Map<string, Cell>();
23	  for (const cell of liveCells) {
24	    for (const neighbor of neighborPositions(cell)) {
25	      const key = `${neighbor[0]},${neighbor[1]}`;
26	      if (!seen.has(key) && !isAlive(neighbor, liveCells)) {
27	        seen.set(key, neighbor);
28	      }
29	    }
30	  }
31	  return [...seen.values()];
32	};
33	
34	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
35	  const survivors = liveCells.filter((cell) => {
36	    const neighbors = countLiveNeighbors(cell, liveCells);
37	    return neighbors === 2 || neighbors === 3;
38	  });
39	
40	  const born = findDeadNeighbors(liveCells).filter(
41	    (cell) => countLiveNeighbors(cell, liveCells) === 3
42	  );
43	
44	  return [...survivors, ...born];
45	};
